/**
 * Integration tests for agentic workflow
 * Tests the complete flow from user input to tool execution
 */

import { jest } from '@jest/globals';
import AgentOrchestrator from '../src/agent/AgentOrchestrator.js';
import ToolRegistry from '../src/tools/ToolRegistry.js';
import ApprovalManager from '../src/agent/ApprovalManager.js';
import ContextManager from '../src/context/ContextManager.js';
import MistralClient from '../src/ai/MistralClient.js';
import FileSystemManager from '../src/filesystem/FileSystemManager.js';
import SearchEngine from '../src/search/SearchEngine.js';
import CodebaseIndexer from '../src/indexer/CodebaseIndexer.js';
import TerminalInterface from '../src/cli/TerminalInterface.js';

// Import tool handlers
import {
  createReadFileHandler, readFileSchema,
  createWriteFileHandler, writeFileSchema,
  createListDirectoryHandler, listDirectorySchema
} from '../src/tools/handlers/index.js';

describe('Agentic Workflow Integration', () => {
  let agentOrchestrator;
  let toolRegistry;
  let approvalManager;
  let contextManager;
  let mistralClient;
  let fileSystemManager;
  let searchEngine;
  let codebaseIndexer;
  let terminalInterface;

  beforeEach(async () => {
    // Mock configuration
    const mockConfig = {
      mistral: {
        apiKey: 'test-api-key',
        model: 'mistral-large-latest',
        maxTokens: 4000,
        temperature: 0.7
      },
      context: {
        maxTokens: 8000
      },
      agent: {
        autonomyMode: 'safe',
        autoApproveTools: [],
        dangerousCommands: ['rm -rf', 'sudo'],
        maxToolCalls: 10
      },
      ui: {
        syntaxHighlight: true,
        theme: 'default'
      },
      logging: {
        level: 'info'
      }
    };

    // Initialize components
    fileSystemManager = new FileSystemManager(process.cwd(), []);
    codebaseIndexer = new CodebaseIndexer(process.cwd(), fileSystemManager);
    searchEngine = new SearchEngine(codebaseIndexer);
    terminalInterface = new TerminalInterface(mockConfig.ui);
    
    // Mock Mistral client
    mistralClient = new MistralClient(mockConfig.mistral.apiKey, mockConfig.mistral);
    
    // Mock the sendWithTools method to simulate AI responses
    mistralClient.sendWithTools = jest.fn();
    mistralClient.registerTools = jest.fn();

    // Initialize tool registry
    toolRegistry = new ToolRegistry(fileSystemManager, searchEngine);
    
    // Register some basic tools for testing
    toolRegistry.registerTool('read_file', readFileSchema, createReadFileHandler(fileSystemManager));
    toolRegistry.registerTool('write_file', writeFileSchema, createWriteFileHandler(fileSystemManager));
    toolRegistry.registerTool('list_directory', listDirectorySchema, createListDirectoryHandler(fileSystemManager));

    // Initialize approval manager
    approvalManager = new ApprovalManager(mockConfig, terminalInterface);
    
    // Mock approval to auto-approve for testing
    approvalManager.requestApproval = jest.fn().mockResolvedValue(true);

    // Initialize context manager
    contextManager = new ContextManager(mockConfig.context.maxTokens);

    // Initialize agent orchestrator
    agentOrchestrator = new AgentOrchestrator(
      mistralClient,
      toolRegistry,
      approvalManager,
      {
        maxToolCalls: mockConfig.agent.maxToolCalls,
        maxIterations: 5,
        streamResponses: false,
        displayToolCalls: false
      }
    );
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('Basic Agent Workflow', () => {
    test('should process message without tool calls', async () => {
      // Mock AI response without tool calls
      mistralClient.sendWithTools.mockResolvedValue({
        content: 'Hello! I can help you with your code.',
        toolCalls: null,
        finishReason: 'stop',
        usage: { totalTokens: 50 }
      });

      const result = await agentOrchestrator.processMessage(
        'Hello, can you help me?',
        contextManager
      );

      expect(result.content).toBe('Hello! I can help you with your code.');
      expect(result.iterations).toBe(1);
      expect(result.toolCallsUsed).toBe(0);
      expect(mistralClient.sendWithTools).toHaveBeenCalledTimes(1);
    });

    test('should process message with single tool call', async () => {
      // Mock AI response with tool call
      mistralClient.sendWithTools
        .mockResolvedValueOnce({
          content: null,
          toolCalls: [{
            id: 'call_123',
            function: {
              name: 'read_file',
              arguments: JSON.stringify({ path: 'package.json' })
            }
          }],
          finishReason: 'tool_calls'
        })
        .mockResolvedValueOnce({
          content: 'I can see your package.json file. It looks like a Node.js project.',
          toolCalls: null,
          finishReason: 'stop',
          usage: { totalTokens: 100 }
        });

      const result = await agentOrchestrator.processMessage(
        'Can you read my package.json file?',
        contextManager
      );

      expect(result.content).toBe('I can see your package.json file. It looks like a Node.js project.');
      expect(result.iterations).toBe(2);
      expect(result.toolCallsUsed).toBe(1);
      expect(mistralClient.sendWithTools).toHaveBeenCalledTimes(2);
      expect(approvalManager.requestApproval).toHaveBeenCalledWith('read_file', { path: 'package.json' });
    });

    test('should handle multiple tool calls in sequence', async () => {
      // Mock AI responses with multiple tool calls
      mistralClient.sendWithTools
        .mockResolvedValueOnce({
          content: null,
          toolCalls: [{
            id: 'call_1',
            function: {
              name: 'list_directory',
              arguments: JSON.stringify({ path: '.' })
            }
          }],
          finishReason: 'tool_calls'
        })
        .mockResolvedValueOnce({
          content: null,
          toolCalls: [{
            id: 'call_2',
            function: {
              name: 'read_file',
              arguments: JSON.stringify({ path: 'README.md' })
            }
          }],
          finishReason: 'tool_calls'
        })
        .mockResolvedValueOnce({
          content: 'I\'ve analyzed your project structure and README file.',
          toolCalls: null,
          finishReason: 'stop',
          usage: { totalTokens: 150 }
        });

      const result = await agentOrchestrator.processMessage(
        'Analyze my project structure',
        contextManager
      );

      expect(result.content).toBe('I\'ve analyzed your project structure and README file.');
      expect(result.iterations).toBe(3);
      expect(result.toolCallsUsed).toBe(2);
      expect(mistralClient.sendWithTools).toHaveBeenCalledTimes(3);
    });

    test('should handle tool execution failure gracefully', async () => {
      // Mock AI response with tool call that will fail
      mistralClient.sendWithTools
        .mockResolvedValueOnce({
          content: null,
          toolCalls: [{
            id: 'call_fail',
            function: {
              name: 'read_file',
              arguments: JSON.stringify({ path: 'nonexistent-file.txt' })
            }
          }],
          finishReason: 'tool_calls'
        })
        .mockResolvedValueOnce({
          content: 'I couldn\'t read that file because it doesn\'t exist.',
          toolCalls: null,
          finishReason: 'stop',
          usage: { totalTokens: 75 }
        });

      const result = await agentOrchestrator.processMessage(
        'Read nonexistent-file.txt',
        contextManager
      );

      expect(result.content).toBe('I couldn\'t read that file because it doesn\'t exist.');
      expect(result.iterations).toBe(2);
      expect(result.toolCallsUsed).toBe(1);
      
      // Check that the tool call history includes the failed call
      const stats = agentOrchestrator.getToolCallStats();
      expect(stats.totalCalls).toBe(1);
      expect(stats.failedCalls).toBe(1);
    });

    test('should respect maximum iterations limit', async () => {
      // Mock AI to always return tool calls (infinite loop scenario)
      mistralClient.sendWithTools.mockResolvedValue({
        content: null,
        toolCalls: [{
          id: 'call_loop',
          function: {
            name: 'list_directory',
            arguments: JSON.stringify({ path: '.' })
          }
        }],
        finishReason: 'tool_calls'
      });

      const result = await agentOrchestrator.processMessage(
        'Keep listing directories',
        contextManager
      );

      expect(result.error).toBe(true);
      expect(result.finishReason).toBe('max_iterations');
      expect(result.iterations).toBe(5); // maxIterations set to 5 in beforeEach
    });
  });

  describe('Tool Registry Integration', () => {
    test('should register and execute tools correctly', async () => {
      const toolNames = toolRegistry.getToolNames();
      expect(toolNames).toContain('read_file');
      expect(toolNames).toContain('write_file');
      expect(toolNames).toContain('list_directory');

      const toolDefinitions = toolRegistry.getToolDefinitions();
      expect(toolDefinitions).toHaveLength(3);
      expect(toolDefinitions[0].type).toBe('function');
      expect(toolDefinitions[0].function.name).toBeDefined();
    });

    test('should validate tool parameters', async () => {
      // Test with missing required parameter
      const result = await toolRegistry.executeTool('read_file', {});
      expect(result.success).toBe(false);
      expect(result.error).toContain('Missing required parameter');
    });
  });

  describe('Approval Manager Integration', () => {
    test('should auto-approve safe tools in safe mode', () => {
      approvalManager.setAutonomyMode('safe');
      
      expect(approvalManager.isAutoApproved('read_file')).toBe(true);
      expect(approvalManager.isAutoApproved('list_directory')).toBe(true);
      expect(approvalManager.isAutoApproved('write_file')).toBe(false);
    });

    test('should detect dangerous operations', () => {
      const dangerousCommand = { command: 'rm -rf /' };
      const safeCommand = { command: 'ls -la' };
      
      expect(approvalManager.isDangerous('execute_command', dangerousCommand)).toBe(true);
      expect(approvalManager.isDangerous('execute_command', safeCommand)).toBe(false);
    });

    test('should change autonomy modes correctly', () => {
      approvalManager.setAutonomyMode('autonomous');
      expect(approvalManager.getAutonomyMode()).toBe('autonomous');
      
      approvalManager.setAutonomyMode('full');
      expect(approvalManager.getAutonomyMode()).toBe('full');
    });
  });

  describe('Context Management', () => {
    test('should maintain conversation context through agent workflow', async () => {
      // Add initial message
      contextManager.addMessage('user', 'Hello');
      
      // Mock AI response
      mistralClient.sendWithTools.mockResolvedValue({
        content: 'Hi there!',
        toolCalls: null,
        finishReason: 'stop',
        usage: { totalTokens: 25 }
      });

      await agentOrchestrator.processMessage('How are you?', contextManager);

      const messages = contextManager.getMessages();
      expect(messages).toHaveLength(3); // Initial + user + assistant
      expect(messages[0].content).toBe('Hello');
      expect(messages[1].content).toBe('How are you?');
      expect(messages[2].content).toBe('Hi there!');
    });
  });

  describe('Error Handling', () => {
    test('should handle invalid tool calls gracefully', async () => {
      // Mock AI response with invalid tool call
      mistralClient.sendWithTools.mockResolvedValue({
        content: null,
        toolCalls: [{
          id: 'call_invalid',
          function: {
            name: 'nonexistent_tool',
            arguments: '{}'
          }
        }],
        finishReason: 'tool_calls'
      });

      // This should not throw an error
      const result = await agentOrchestrator.processMessage(
        'Use invalid tool',
        contextManager
      );

      // The agent should handle the error and continue
      expect(result).toBeDefined();
      expect(result.iterations).toBeGreaterThan(0);
    });

    test('should handle malformed tool arguments', async () => {
      // Mock AI response with malformed JSON arguments
      mistralClient.sendWithTools.mockResolvedValue({
        content: null,
        toolCalls: [{
          id: 'call_malformed',
          function: {
            name: 'read_file',
            arguments: 'invalid json'
          }
        }],
        finishReason: 'tool_calls'
      });

      const result = await agentOrchestrator.processMessage(
        'Read file with bad args',
        contextManager
      );

      expect(result).toBeDefined();
      
      // Check that the error was recorded
      const stats = agentOrchestrator.getToolCallStats();
      expect(stats.failedCalls).toBeGreaterThan(0);
    });
  });
});